DELETE FROM price_snapshots ps
USING parts p
WHERE ps.part_id = p.id
  AND ps.source = 'DANAWA_PRICE_TREND'
  AND NOT EXISTS (
    SELECT 1
    FROM verified_parts vp
    WHERE vp.public_id = p.public_id
      AND vp.product_code = ps.raw_payload->>'productCode'
  );

ON CONFLICT (part_id, source, collected_at) WHERE source = 'DANAWA_PRICE_TREND'
DO UPDATE SET
  price = EXCLUDED.price,
  raw_payload = EXCLUDED.raw_payload;
